const e=JSON.parse('{"key":"v-16c875b4","path":"/tech/redis/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%8404-%E5%BF%AB%E9%80%9F%E9%93%BE%E8%A1%A8.html","title":"数据结构04-快速链表","lang":"zh-CN","frontmatter":{"date":"2021-12-06T22:13:00.000Z","category":["Redis"],"tag":["Redis","算法"],"description":"数据结构04-快速链表 img （开局一张图，下面全靠编） 在Redis 3.2之前的版本，Redis使用压缩链表（ziplist）和双端链表（adlist）来实现List。当元素个数比较少的情况下，使用压缩链表，当数据到一定的量，升级为双端链表。这是因为压缩链表可以节省内存空间，但压缩链表的数据是连续的，数据的插入压缩链表需要重新分配内存，这会影响到压缩链表的执行效率，所以升级到双端链表。快速链表是综合考虑时间效率和空间效率引入的新型数据结构。","head":[["meta",{"property":"og:url","content":"https://dhbin.cn/tech/redis/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%8404-%E5%BF%AB%E9%80%9F%E9%93%BE%E8%A1%A8.html"}],["meta",{"property":"og:site_name","content":"DHB"}],["meta",{"property":"og:title","content":"数据结构04-快速链表"}],["meta",{"property":"og:description","content":"数据结构04-快速链表 img （开局一张图，下面全靠编） 在Redis 3.2之前的版本，Redis使用压缩链表（ziplist）和双端链表（adlist）来实现List。当元素个数比较少的情况下，使用压缩链表，当数据到一定的量，升级为双端链表。这是因为压缩链表可以节省内存空间，但压缩链表的数据是连续的，数据的插入压缩链表需要重新分配内存，这会影响到压缩链表的执行效率，所以升级到双端链表。快速链表是综合考虑时间效率和空间效率引入的新型数据结构。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-23T12:17:45.000Z"}],["meta",{"property":"article:author","content":"DHB"}],["meta",{"property":"article:tag","content":"Redis"}],["meta",{"property":"article:tag","content":"算法"}],["meta",{"property":"article:published_time","content":"2021-12-06T22:13:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-23T12:17:45.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"数据结构04-快速链表\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-12-06T22:13:00.000Z\\",\\"dateModified\\":\\"2023-03-23T12:17:45.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"DHB\\",\\"url\\":\\"https://dhbin.cn\\"}]}"]]},"headers":[{"level":2,"title":"原理","slug":"原理","link":"#原理","children":[]},{"level":2,"title":"数据结构","slug":"数据结构","link":"#数据结构","children":[{"level":3,"title":"quicklist","slug":"quicklist","link":"#quicklist","children":[]},{"level":3,"title":"quicklistNode","slug":"quicklistnode","link":"#quicklistnode","children":[]}]},{"level":2,"title":"逻辑","slug":"逻辑","link":"#逻辑","children":[{"level":3,"title":"如何判断quicklistNode能否继续插入数据","slug":"如何判断quicklistnode能否继续插入数据","link":"#如何判断quicklistnode能否继续插入数据","children":[]},{"level":3,"title":"初始化","slug":"初始化","link":"#初始化","children":[]},{"level":3,"title":"数据插入","slug":"数据插入","link":"#数据插入","children":[]},{"level":3,"title":"其他","slug":"其他","link":"#其他","children":[]}]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[]}],"git":{"createdTime":1679573865000,"updatedTime":1679573865000,"contributors":[{"name":"dhb","email":"xx158@qq.com","commits":1}]},"readingTime":{"minutes":9.32,"words":2796},"filePathRelative":"tech/redis/数据结构04-快速链表.md","localizedDate":"2021年12月6日","excerpt":"<h1> 数据结构04-快速链表</h1>\\n<figure><img src=\\"https://cdn.dhbin.cn/202303232003998.jpeg\\" alt=\\"img\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption>img</figcaption></figure>\\n<p>（开局一张图，下面全靠编）</p>\\n<p>在Redis 3.2之前的版本，Redis使用压缩链表（ziplist）和双端链表（adlist）来实现List。当元素个数比较少的情况下，使用压缩链表，当数据到一定的量，升级为双端链表。这是因为压缩链表可以节省内存空间，但压缩链表的数据是连续的，数据的插入压缩链表需要重新分配内存，这会影响到压缩链表的执行效率，所以升级到双端链表。快速链表是综合考虑时间效率和空间效率引入的新型数据结构。</p>","autoDesc":true}');export{e as data};
